33	export function runQuery<T extends QueryParameter[]>(
34	    world: World,
35	    query: QueryInstance<T>,
36	    params: QueryParameter[]
37	): QueryResult<T> {
38	    commitQueryRemovals(world);
39	
40	    // With hybrid bitmask strategy, query.entities is already incrementally maintained
41	    // with both trait and relation filters applied. Just return the pre-filtered entities.
42	    const entities = query.entities.dense.slice() as Entity[];
43	
44	    // Clear so it can accumulate again.
45	    if (query.isTracking) {
46	        query.entities.clear();
47	        // PERF: Use indexed loop instead of for...of
48	        const len = entities.length;
49	        for (let i = 0; i < len; i++) {
50	            query.resetTrackingBitmasks(entities[i]);
51	        }
52	    }
53	
54	    return createQueryResult(world, entities, query, params);
