import type { Entity } from '../entity/types';
import { addTrait, getTrait, hasTrait, removeTrait, setTrait } from '../trait/trait';
import type { ConfigurableTrait, Trait } from '../trait/types';
import type { World } from '../world';
import type { QueryUnsubscriber } from '../query/types';
import { $aspect } from './symbols';
import type { Aspect, AspectConstituent } from './types';
import { isAspect } from './utils/is-aspect';

let aspectId = 0;

/**
 * Creates an aspect from two or more traits (or nested aspects).
 * Nested aspects are flattened to their individual constituent traits.
 * Overlapping field names between constituents, and relation constituents,
 * throw an error at creation time.
 */
export function createAspect<T extends AspectConstituent[]>(...constituents: T): Aspect<any> {
    if (constituents.length < 2) {
        throw new Error('Koota: createAspect requires at least two constituents.');
    }

    // Flatten nested aspects to their individual traits.
    const flattened: Trait[] = [];
    for (const constituent of constituents) {
        if (isAspect(constituent)) {
            flattened.push(...constituent[$internal].traits);
        } else {
            flattened.push(constituent as Trait);
        }
    }

    // De-duplicate identical trait references (e.g. shared via multiple nested aspects).
    const traits: Trait[] = [];
    const seenTraits = new Set<Trait>();
    for (const trait of flattened) {
        if (seenTraits.has(trait)) continue;
        seenTraits.add(trait);
        traits.push(trait);
    }

    // Relation constituents are not allowed.
    for (const trait of traits) {
        if (trait[$internal].relation !== null) {
            throw new Error('Koota: Relation traits cannot be used as aspect constituents.');
        }
    }

    // Overlapping field names between constituents are not allowed.
    const seenFields = new Map<string, Trait>();
    for (const trait of traits) {
        const traitCtx = trait[$internal];
        if (traitCtx.type !== 'soa') continue;
        for (const key in trait.schema) {
            const owner = seenFields.get(key);
            if (owner) {
                throw new Error(
                    `Koota: Aspect field "${key}" is defined by multiple constituent traits.`
                );
            }
            seenFields.set(key, trait);
        }
    }

    const schema: Record<string, unknown> = {};
    for (const trait of traits) {
        if (trait[$internal].type === 'soa') Object.assign(schema, trait.schema);
    }

    const id = aspectId++;
    const aspect = {
        [$aspect]: true,
        id,
        traits,
        schema,
        [$internal]: { id, traits },
    } as Aspect<any>;

    return Object.freeze(aspect);
}

export const aspect = createAspect;

export function hasAspect(world: World, entity: Entity, asp: Aspect): boolean {
    const traits = asp[$internal].traits;
    for (let i = 0; i < traits.length; i++) {
        if (!hasTrait(world, entity, traits[i])) return false;
    }
    return true;
}

export function getAspect(world: World, entity: Entity, asp: Aspect): Record<string, any> | undefined {
    const traits = asp[$internal].traits;
    const result: Record<string, any> = {};
    for (let i = 0; i < traits.length; i++) {
        const trait = traits[i];
        if (!hasTrait(world, entity, trait)) return undefined;
        if (trait[$internal].type === 'tag') continue;
        Object.assign(result, getTrait(world, entity, trait));
    }
    return result;
}

export function setAspect(world: World, entity: Entity, asp: Aspect, value: Record<string, any>) {
    const traits = asp[$internal].traits;
    for (let i = 0; i < traits.length; i++) {
        const trait = traits[i];
        if (trait[$internal].type === 'tag') continue;
        setTrait(world, entity, trait, value, true);
    }
}

export function addAspect(world: World, entity: Entity, asp: Aspect, value?: Record<string, any>) {
    const traits = asp[$internal].traits;
    const toAdd: ConfigurableTrait[] = [];

    for (const trait of traits) {
        if (hasTrait(world, entity, trait)) continue;
        toAdd.push(value ? [trait, value] : trait);
    }

    if (toAdd.length > 0) addTrait(world, entity, ...toAdd);
}

export function removeAspect(world: World, entity: Entity, asp: Aspect) {
    removeTrait(world, entity, ...asp[$internal].traits);
}

export function onAspectAdd(
